import { Anthropic } from '@anthropic-ai/sdk';

const tools = [
  {
    name: 'search_kb',
    description: 'Search support knowledge base',
    input_schema: {
      type: 'object',
      properties: { query: { type: 'string' } }
    }
  },
  {
    name: 'lookup_order',
    description: 'Lookup customer order',
    input_schema: {
      type: 'object',
      properties: { order_id: { type: 'string' } }
    }
  }
] as const;

const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });

async function handleSupportQuery(query: string) {
  let message = await client.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools,
    messages: [{ role: 'user', content: query }]
  });

  while (message.stop_reason === 'tool_use') {
    const toolResults = [];
    for (const toolUse of message.tool_use?.contents ?? []) {
      if (toolUse.name === 'lookup_order') {
        const order = await crm.lookupOrder(toolUse.input.order_id);
        toolResults.push({
          type: 'tool_result',
          tool_use_id: toolUse.id,
          content: [{ type: 'text', text: JSON.stringify(order) }]
        });
      }
    }
    message = await client.messages.create({
      model: 'claude-3-5-sonnet-20240620',
      tools,
      messages: [...message.content, ...toolResults]
    });
  }
  return message.content[0].text;
}

